const data = msg.payload || {};

let voltage = 0;
let battery = 80;
let power = 0;
let current = 0;
let temperature = 25.0;
let humidity = 50.0;
let relay = false;
let gridPresent = true;
let dc_voltage = 0;

// 1. Detect and Normalize input source
if (typeof data.ac_voltage !== 'undefined') {
    // Payload from real ESP32
    voltage = Number(data.ac_voltage || 0);
    power = Number(data.ac_power || 0);
    current = Number(data.ac_current || 0);
    temperature = Number(data.temperature || 25.0);
    humidity = Number(data.humidity || 50.0);
    relay = Boolean(data.relay);
    gridPresent = Boolean(data.gridPresent);
    dc_voltage = Number(data.dc_voltage || 0);

    // Normalize battery status: map humidity range to battery state
    battery = Number(humidity);
} else {
    // Payload from simulator
    voltage = Number(data.voltage || 0);
    battery = Number(data.battery || 0);
    power = Number(data.power || 0);
    current = Number(data.current || (voltage > 0 ? (power / voltage) : 0));
    temperature = Number(data.temperature || 25.0);
    humidity = Number(data.humidity || 50.0);
    relay = Boolean(data.relay);
    gridPresent = Boolean(data.gridPresent);
    dc_voltage = Number(data.dc_voltage || (battery / 100 * 12.0));
}

// 2. Validation / Rejection Layer
if (voltage < 0 || power < 0 || battery < 0 || battery > 100) {
    node.warn("Telemetry rejected due to validation failure: " + JSON.stringify({voltage, power, battery}));
    return null;
}

// 3. Data Cleaning / Outlier filtering
voltage = Math.max(0, Math.min(300, voltage));
battery = Math.max(0, Math.min(100, battery));
power = Math.max(0, Math.min(5000, power));
current = Math.max(0, Math.min(25, current));
dc_voltage = Math.max(0, Math.min(50, dc_voltage));

// Output 1: InfluxDB line protocol
const timestamp = Date.now();
let extraFields = "";
if (typeof data.sent_at !== 'undefined') {
    extraFields = ",sent_at=" + data.sent_at;
}
const line = `ecoedge,device=device01 voltage=${voltage.toFixed(2)},battery=${battery.toFixed(2)},power=${power.toFixed(2)},temperature=${temperature.toFixed(2)},humidity=${humidity.toFixed(2)},relay=${relay},gridPresent=${gridPresent},dc_voltage=${dc_voltage.toFixed(2)}${extraFields} ${timestamp}`;

const msg1 = {
    payload: line,
    headers: {
        "Authorization": "Token 03VDOT3tpzwm7--nywROtKR0SPBpWTRZmPiVla6jw_5tgaP8syQQxARVt8d74OnGh0afh6Z85xgM1gRc6XF8lQ==",
        "Content-Type": "text/plain; charset=utf-8"
    }
};

// Output 2: Canonical Normalized JSON object
const normalizedObj = {
    device_id: "device01",
    timestamp: new Date().toISOString(),
    voltage: Number(voltage.toFixed(2)),
    current: Number(current.toFixed(2)),
    power: Number(power.toFixed(2)),
    battery: Number(battery.toFixed(2)),
    dc_voltage: Number(dc_voltage.toFixed(2)),
    battery_source: typeof data.ac_voltage !== 'undefined' ? "humidity_derived" : "simulated",
    temperature: Number(temperature.toFixed(2)),
    humidity: Number(humidity.toFixed(2)),
    grid_present: gridPresent,
    relay_status: relay,
    source: typeof data.ac_voltage !== 'undefined' ? "esp32" : "simulator",
    sent_at: typeof data.sent_at !== 'undefined' ? Number(data.sent_at) : undefined
};

const msg2 = {
    payload: normalizedObj
};

return [msg1, msg2];
